1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Damage = { itemType: string; amount: number };
7	type Incident = { cause: string; damages: Damage[] };
8	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
9	type Step = QuoteStep | ClaimStep;
10	type Scenario = { customer: Customer; steps: Step[] };
11	type QuoteResult = { premium: number };
12	type ClaimResult = { payout: number; remainingCap: number };
13	type StepResult = QuoteResult | ClaimResult;
14	type ScenarioResult = { results: StepResult[] };
15	
16	const BASE_PRICES: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	  moonstone: 25,
23	};
24	
25	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
26	
27	const CURSED_SURCHARGE_RATE = 0.5;
28	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
29	const HIGH_ENCHANTMENT_THRESHOLD = 5;
30	
31	const isCursed = (item: Item): boolean => item.cursed === true;
32	const isHighlyEnchanted = (item: Item): boolean =>
33	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
34	
35	const surchargeRate = (item: Item): number =>
36	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
37	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
38	
39	const itemSurchargeAmount = (item: Item): number =>
40	  basePriceOf(item) * surchargeRate(item);
41	
42	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
43	const BLOCK_SIZE = 3;
44	const BLOCK_PRICE = 60;
45	
46	const groupByType = (items: Item[]): Map<string, Item[]> =>
47	  items.reduce((groups, item) => {
48	    const existing = groups.get(item.type) ?? [];
49	    return groups.set(item.type, [...existing, item]);
50	  }, new Map<string, Item[]>());
51	
52	const qualifiesForComponentBlock = (type: string, members: Item[]): boolean =>
53	  COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE;
54	
55	const groupBasePremium = (type: string, members: Item[]): number => {
56	  if (qualifiesForComponentBlock(type, members)) return BLOCK_PRICE;
57	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
58	};
59	
60	const itemsBaseSubtotal = (items: Item[]): number =>
61	  Array.from(groupByType(items)).reduce(
62	    (total, [type, members]) => total + groupBasePremium(type, members),
63	    0,
64	  );
65	
66	const itemsSurchargeSubtotal = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
68	
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	
72	const isLoyalCustomer = (customer: Customer): boolean =>
73	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
74	
75	const loyaltyDiscountRate = (customer: Customer): number =>
76	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
77	
78	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
79	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
80	
81	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
82	
83	const followUpDiscountRate = (stepIndex: number): number =>
84	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
85	
86	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
87	  FIRST_INSURANCE_SURCHARGE_RATE -
88	  loyaltyDiscountRate(customer) -
89	  followUpDiscountRate(stepIndex);
90	
91	const quotePremium = (
92	  items: Item[],
93	  customer: Customer,
94	  stepIndex: number,
95	): number => {
96	  const baseSubtotal = itemsBaseSubtotal(items);
97	  const surchargeSubtotal = itemsSurchargeSubtotal(items);
98	  // Kept as `base + base*rate` (not `base*(1+rate)`) for IEEE-754 stability:
99	  // e.g. 100*(1+0.1) === 110.00000000000001, which trips Math.ceil rounding.
100	  return (
101	    baseSubtotal +
102	    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
103	    surchargeSubtotal +
104	    PROCESSING_FEE
105	  );
106	};
107	
108	// MHPCO always rounds in its own favor: premiums up, payouts down.
109	const roundPremiumInMhpcoFavor = (amount: number): number => Math.ceil(amount);
110	
111	const INSURANCE_VALUES: Record<string, number> = {
112	  sword: 1000,
113	  amulet: 600,
114	  staff: 800,
115	  potion: 400,
116	  rune: 250,
117	  moonstone: 250,
118	};
119	
120	const insuranceValueOf = (item: Item): number => INSURANCE_VALUES[item.type] ?? 0;
121	
122	const DEDUCTIBLE_PER_DAMAGE = 100;
123	const CAP_MULTIPLIER = 2;
124	
125	const insuranceSum = (items: Item[]): number =>
126	  items.reduce((sum, item) => sum + insuranceValueOf(item), 0);
127	
128	const damagePayout = (damage: Damage): number =>
129	  damage.amount - DEDUCTIBLE_PER_DAMAGE;
130	
131	const runQuoteStep = (
132	  step: QuoteStep,
133	  customer: Customer,
134	  stepIndex: number,
135	): QuoteResult => ({
136	  premium: roundPremiumInMhpcoFavor(quotePremium(step.items, customer, stepIndex)),
137	});
138	
139	const runClaimStep = (step: ClaimStep, policyItems: Item[]): ClaimResult => {
140	  const payout = step.incident.damages.reduce(
141	    (sum, damage) => sum + damagePayout(damage),
142	    0,
143	  );
144	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
145	  return { payout, remainingCap: cap - payout };
146	};
147	
148	const runStep = (
149	  step: Step,
150	  customer: Customer,
151	  stepIndex: number,
152	  steps: Step[],
153	): StepResult => {
154	  if (step.op === "quote") return runQuoteStep(step, customer, stepIndex);
155	  const policyStep = steps[step.policy] as QuoteStep;
156	  return runClaimStep(step, policyStep.items);
157	};
158	
159	export const runScenario = (input: Scenario): ScenarioResult => ({
160	  results: input.steps.map((step, i) =>
161	    runStep(step, input.customer, i, input.steps),
162	  ),
163	});
